+	if strings.HasPrefix(absPath, "/var/home/") {
+		return true
+	}
+
 	for _, prefix := range unsafePrefixes {
 		if strings.HasPrefix(absPath, prefix+"/") || absPath == prefix {
 			return false
 		}
 	}
 	// Also reject other users' home directories
 	homeDir, _ := os.UserHomeDir()
